override fun requestDelegate(
    request: ImageRequest,
    job: Job,
    findLifecycle: Boolean,
): RequestDelegate {
    val target = request.target
    if (target is ViewTarget<*>) {
        val lifecycle = request.lifecycle ?: request.findLifecycle()
        return ViewTargetRequestDelegate(imageLoader, request, target, lifecycle, job)
    }

    val lifecycle = request.lifecycle ?: if (findLifecycle) request.findLifecycle() else null
    if (lifecycle != null) {
        return LifecycleRequestDelegate(lifecycle, job)
    }

    return BaseRequestDelegate(job)
}

private fun isConfigValidForHardware(
    request: ImageRequest,
    requestedConfig: Bitmap.Config,
): Boolean {
    // Short circuit if the requested bitmap config is software.
    if (!requestedConfig.isHardware) {
        return true
    }

    // Ensure the request allows hardware bitmaps.
    if (!request.allowHardware) {
        return false
    }

    // Prevent hardware bitmaps for non-hardware accelerated targets.
    val target = request.target
    if (target is ViewTarget<*> &&
        target.view.run { isAttachedToWindow && !isHardwareAccelerated }
    ) {
        return false
    }

    return true
}

@VisibleForTesting
    internal fun isCacheValueValid(
        request: ImageRequest,
        cacheKey: MemoryCache.Key,
        cacheValue: MemoryCache.Value,
        size: Size,
        scale: Scale,
    ): Boolean {
        // Ensure we don't return a hardware bitmap if the request doesn't allow it.
        if (!requestService.isCacheValueValidForHardware(request, cacheValue)) {
            logger?.log(TAG, Logger.Level.Debug) {
                "${request.data}: Cached bitmap is hardware-backed, " +
                    "which is incompatible with the request."
            }
            return false
        }

        // Ensure the size of the cached bitmap is valid for the request.
        return isCacheValueValidForSize(request, cacheKey, cacheValue, size, scale)
    }

override suspend fun execute(request: ImageRequest): ImageResult {
    if (!needsExecuteOnMainDispatcher(request)) {
        // Fast path: skip dispatching.
        return execute(request, REQUEST_TYPE_EXECUTE)
    } else {
        // Slow path: dispatch to the main thread.
        return coroutineScope {
            // Start executing the request on the main thread.
            val job = async(options.mainCoroutineContextLazy.value) {
                execute(request, REQUEST_TYPE_EXECUTE)
            }

            // Update the current request attached to the view and await the result.
            getDisposable(request, job).job.await()
        }
    }
}

private suspend fun wrapDrawable(baseDrawable: Drawable): Drawable {
    if (baseDrawable !is AnimatedImageDrawable) {
        return baseDrawable
    }

    if (options.repeatCount != ENCODED_LOOP_COUNT) {
        baseDrawable.repeatCount = options.repeatCount
    }

    // Set the start and end animation callbacks if any one is supplied through the request.
    val onStart = options.animationStartCallback
    val onEnd = options.animationEndCallback
    if (onStart != null || onEnd != null) {
        // Animation callbacks must be set on the main thread.
        withContext(Dispatchers.Main.immediate) {
            baseDrawable.registerAnimationCallback(animatable2CallbackOf(onStart, onEnd))
        }
    }

    // Wrap AnimatedImageDrawable in a ScaleDrawable so it always scales to fill its bounds.
    return ScaleDrawable(baseDrawable, options.scale)
}

private fun drawFrame(canvas: Canvas) {
    val softwareCanvas = softwareCanvas
    val softwareBitmap = softwareBitmap
    if (softwareCanvas == null || softwareBitmap == null) return

    // Clear the software canvas.
    softwareCanvas.drawColor(Color.TRANSPARENT, PorterDuff.Mode.CLEAR)

    // Draw onto a software canvas first.
    softwareCanvas.withSave {
        scale(softwareScale, softwareScale)
        movie.draw(this, 0f, 0f, paint)
        animatedTransformationPicture?.draw(this)
    }

    // Draw onto the input canvas (may or may not be hardware).
    canvas.withSave {
        translate(hardwareDx, hardwareDy)
        scale(hardwareScale, hardwareScale)
        drawBitmap(softwareBitmap, 0f, 0f, paint)
    }
}

override suspend fun write(
    cacheResponse: NetworkResponse?,
    networkRequest: NetworkRequest,
    networkResponse: NetworkResponse,
    options: Options,
): WriteResult {
    val responseCaching = CacheControl.parse(networkResponse.headers)
    val requestCaching = CacheControl.parse(networkRequest.headers)
    if (!isCacheable(responseCaching, requestCaching)) {
        return WriteResult.DISABLED
    }

    // Fall back to the default cache write strategy.
    return CacheStrategy.DEFAULT.write(cacheResponse, networkRequest, networkResponse, options)
}

open fun create(context: ResolutionContext): T {
    context.logger.debug("| (+) '$beanDefinition'")
    try {
        val parameters: ParametersHolder = context.parameters ?: emptyParametersHolder()
        return beanDefinition.definition.invoke(
            context.scope,
            parameters,
        )
    } catch (e: Exception) {
        val stack = KoinPlatformTools.getStackTrace(e)
        context.logger.error("* Instance creation error : could not create instance for '$beanDefinition': $stack")
        throw InstanceCreationException("Could not create instance for '$beanDefinition'", e)
    }
}

internal suspend inline fun <T> suspendCancellableCoroutineReusable(
    crossinline block: (CancellableContinuationImpl<T>) -> Unit
): T = suspendCoroutineUninterceptedOrReturn { uCont ->
    val cancellable = getOrCreateCancellableContinuation(uCont.intercepted())
    try {
        block(cancellable)
    } catch (e: Throwable) {
        // Here we catch any unexpected exception from user-supplied block (e.g. invariant violation)
        // and release claimed continuation in order to leave it in a reasonable state (see #3613)
        cancellable.releaseClaimedReusableContinuation()
        throw e
    }
    cancellable.getResult()
}

@ObsoleteCoroutinesApi
@Deprecated(level = DeprecationLevel.ERROR, message = "BroadcastChannel is deprecated in the favour of SharedFlow and is no longer supported")
public fun <E> ReceiveChannel<E>.broadcast(
    capacity: Int = 1,
    start: CoroutineStart = CoroutineStart.LAZY
): BroadcastChannel<E> {
    val scope = GlobalScope + Dispatchers.Unconfined + CoroutineExceptionHandler { _, _ -> }
    val channel = this
    // We can run this coroutine in the context that ignores all exceptions, because of `onCompletion = consume()`
    // which passes all exceptions upstream to the source ReceiveChannel
    return scope.broadcast(capacity = capacity, start = start, onCompletion = { cancelConsumed(it) }) {
        for (e in channel) {
            send(e)
        }
    }
}

@ObsoleteCoroutinesApi
@Deprecated(level = DeprecationLevel.ERROR, message = "BroadcastChannel is deprecated in the favour of SharedFlow and is no longer supported")
public fun <E> CoroutineScope.broadcast(
    context: CoroutineContext = EmptyCoroutineContext,
    capacity: Int = 1,
    start: CoroutineStart = CoroutineStart.LAZY,
    onCompletion: CompletionHandler? = null,
    block: suspend ProducerScope<E>.() -> Unit
): BroadcastChannel<E> {
    val newContext = newCoroutineContext(context)
    val channel = BroadcastChannel<E>(capacity)
    val coroutine = if (start.isLazy)
        LazyBroadcastCoroutine(newContext, channel, block) else
        BroadcastCoroutine(newContext, channel, active = true)
    if (onCompletion != null) coroutine.invokeOnCompletion(handler = onCompletion)
    coroutine.start(start, coroutine, block)
    return coroutine
}

@InternalCoroutinesApi
public fun handleCoroutineException(context: CoroutineContext, exception: Throwable) {
    val reportException = if (exception is DispatchException) exception.cause else exception
    // Invoke an exception handler from the context if present
    try {
        context[CoroutineExceptionHandler]?.let {
            it.handleException(context, reportException)
            return
        }
    } catch (t: Throwable) {
        handleUncaughtCoroutineException(context, handlerException(reportException, t))
        return
    }
    // If a handler is not present in the context or an exception was thrown, fallback to the global handler
    handleUncaughtCoroutineException(context, reportException)
}

private fun enqueueDelayedTasks() {
    val delayed = _delayed.value
    if (delayed != null && !delayed.isEmpty) {
        val now = nanoTime()
        while (true) {
            // make sure that moving from delayed to queue removes from delayed only after it is added to queue
            // to make sure that 'isEmpty' and `nextTime` that check both of them
            // do not transiently report that both delayed and queue are empty during move
            delayed.removeFirstIf {
                if (it.timeToExecute(now)) {
                    enqueueImpl(it)
                } else
                    false
            } ?: break // quit loop when nothing more to remove or enqueueImpl returns false on "isComplete"
        }
    }
}

internal suspend inline fun <T> Flow<T>.collectWhile(crossinline predicate: suspend (value: T) -> Boolean) {
    val collector = object : FlowCollector<T> {
        override suspend fun emit(value: T) {
            // Note: we are checking predicate first, then throw. If the predicate does suspend (calls emit, for example)
            // the resulting code is never tail-suspending and produces a state-machine
            if (!predicate(value)) {
                throw AbortFlowException(this)
            }
        }
    }
    try {
        collect(collector)
    } catch (e: AbortFlowException) {
        e.checkOwnership(collector)
        // The task might have been cancelled before AbortFlowException was thrown.
        coroutineContext.ensureActive()
    }
}

internal fun handleUncaughtCoroutineException(context: CoroutineContext, exception: Throwable) {
    // use additional extension handlers
    for (handler in platformExceptionHandlers) {
        try {
            handler.handleException(context, exception)
        } catch (_: ExceptionSuccessfullyProcessed) {
            return
        } catch (t: Throwable) {
            propagateExceptionFinalResort(handlerException(exception, t))
        }
    }

    try {
        exception.addSuppressed(DiagnosticCoroutineContextException(context))
    } catch (e: Throwable) {
        // addSuppressed is never user-defined and cannot normally throw with the only exception being OOM
        // we do ignore that just in case to definitely deliver the exception
    }
    propagateExceptionFinalResort(exception)
}

@Suppress("UNUSED_PARAMETER")
    private fun onAwaitInternalRegFunc(select: SelectInstance<*>, ignoredParam: Any?) {
        while (true) {
            val state = this.state
            if (state !is Incomplete) {
                val result = if (state is CompletedExceptionally) state else state.unboxState()
                select.selectInRegistrationPhase(result)
                return
            }
            if (startInternal(state) >= 0) break // break unless needs to retry
        }
        val disposableHandle = invokeOnCompletion(handler = SelectOnAwaitCompletionHandler(select))
        select.disposeOnCompletion(disposableHandle)
    }

@Suppress("UNUSED_PARAMETER")
    private fun register(select: SelectInstance<*>, ignoredParam: Any?) {
        // Should this clause complete immediately?
        if (timeMillis <= 0) {
            select.selectInRegistrationPhase(Unit)
            return
        }
        // Invoke `trySelect` after the timeout is reached.
        val action = Runnable {
            select.trySelect(this@OnTimeout, Unit)
        }
        select as SelectImplementation<*>
        val context = select.context
        val disposableHandle = context.delay.invokeOnTimeout(timeMillis, action, context)
        // Do not forget to clean-up when this `select` is completed or cancelled.
        select.disposeOnCompletion(disposableHandle)
    }

private fun installSignalHandler() {
    try {
        Signal.handle(Signal("TRAP")) { // kill -5
            if (DebugProbesImpl.isInstalled) {
                // Case with 'isInstalled' changed between this check-and-act is not considered
                // a real debug probes use-case, thus is not guarded against.
                DebugProbesImpl.dumpCoroutines(System.out)
            } else {
                println("Cannot perform coroutines dump, debug probes are disabled")
            }
        }
    } catch (t: Throwable) {
        // Do nothing, signal cannot be installed, e.g. because we are on Windows
    }
}

override fun scheduleResumeAfterDelay(timeMillis: Long, continuation: CancellableContinuation<Unit>) {
    val future = (executor as? ScheduledExecutorService)?.scheduleBlock(
        ResumeUndispatchedRunnable(this, continuation),
        continuation.context,
        timeMillis
    )
    // If everything went fine and the scheduling attempt was not rejected -- use it
    if (future != null) {
        continuation.invokeOnCancellation(CancelFutureOnCancel(future))
        return
    }
    // Otherwise fallback to default executor
    DefaultExecutor.scheduleResumeAfterDelay(timeMillis, continuation)
}

private fun <T> reactorPublish(
    scope: CoroutineScope,
    context: CoroutineContext = EmptyCoroutineContext,
    block: suspend ProducerScope<T>.() -> Unit
): Publisher<T> = Publisher onSubscribe@{ subscriber: Subscriber<in T>? ->
    if (subscriber !is CoreSubscriber) {
        subscriber.reject(IllegalArgumentException("Subscriber is not an instance of CoreSubscriber, context can not be extracted."))
        return@onSubscribe
    }
    val currentContext = subscriber.currentContext()
    val reactorContext = context.extendReactorContext(currentContext)
    val newContext = scope.newCoroutineContext(context + reactorContext)
    val coroutine = PublisherCoroutine(newContext, subscriber, REACTOR_HANDLER)
    subscriber.onSubscribe(coroutine) // do it first (before starting coroutine), to avoid unnecessary suspensions
    coroutine.start(CoroutineStart.DEFAULT, coroutine, block)
}

@Suppress("UNCHECKED_CAST")
    @PublishedApi
    internal fun buildTo(builder: SerializersModuleBuilder) {
        if (baseSerializer != null) builder.registerPolymorphicSerializer(baseClass, baseClass, baseSerializer)
        subclasses.forEach { (kclass, serializer) ->
            builder.registerPolymorphicSerializer(
                baseClass,
                kclass as KClass<Base>,
                serializer.cast()
            )
        }

        val defaultDeserializer = defaultDeserializerProvider
        if (defaultDeserializer != null) {
            builder.registerDefaultPolymorphicDeserializer(baseClass, defaultDeserializer, false)
        }
    }

internal fun SerialDescriptor.getJsonNameIndex(json: Json, name: String): Int {
    if (json.decodeCaseInsensitive(this)) {
        return getJsonNameIndexSlowPath(json, name.lowercase())
    }

    val strategy = namingStrategy(json)
    if (strategy != null) return getJsonNameIndexSlowPath(json, name)
    val index = getElementIndex(name)
    // Fast path, do not go through ConcurrentHashMap.get
    // Note, it blocks ability to detect collisions between the primary name and alternate,
    // but it eliminates a significant performance penalty (about -15% without this optimization)
    if (index != CompositeDecoder.UNKNOWN_NAME) return index
    if (!json.configuration.useAlternativeNames) return index
    // Slow path
    return getJsonNameIndexSlowPath(json, name)
}

override fun encodeLong(value: Long) {
    val asDouble = value.toDouble()
    val conversionHasLossOfPrecision = abs(asDouble) > MAX_SAFE_INTEGER
    // todo: shall it be driven by isLenient or another configuration key?
    if (!json.configuration.isLenient && conversionHasLossOfPrecision) {
        throw IllegalArgumentException(
            "$value can't be serialized to number due to a potential precision loss. " +
                    "Use the JsonConfiguration option isLenient to serialize anyway"
        )
    }

    if (currentElementIsMapKey && conversionHasLossOfPrecision) {
        throw IllegalArgumentException(
            "Long with value $value can't be used in json as map key, because its value is larger than Number.MAX_SAFE_INTEGER"
        )
    }

    encodeValue(asDouble)
}

internal fun extractProtoId(descriptor: SerialDescriptor, index: Int, zeroBasedDefault: Boolean): Int {
    val annotations = descriptor.getElementAnnotations(index)
    var result = if (zeroBasedDefault) index else index + 1
    for (i in annotations.indices) { // Allocation-friendly loop
        val annotation = annotations[i]
        if (annotation is ProtoOneOf) {
            // Fast return for one of field
            return ID_HOLDER_ONE_OF
        } else if (annotation is ProtoNumber) {
            result = annotation.number
            // 0 or negative numbers are acceptable for enums
            if (!zeroBasedDefault) {
                checkFieldNumber(result, i, descriptor)
            }
        }
    }
    return result
}

override suspend fun execute(data: HttpRequestData): HttpResponseData {
    val callContext = callContext()

    while (coroutineContext.isActive) {
        val unixSocket = data.getCapabilityOrNull(UnixSocketCapability)
        val endpoint = selectEndpoint(data.url, proxy, unixSocket)

        try {
            return endpoint.execute(data, callContext)
        } catch (_: ClosedSendChannelException) {
            continue
        } finally {
            if (!coroutineContext.isActive) {
                endpoint.close()
            }
        }
    }

    throw ClientEngineClosedException()
}

@OptIn(DelicateCoroutinesApi::class)
internal fun ByteWriteChannel.withoutClosePropagation(
    coroutineContext: CoroutineContext,
    closeOnCoroutineCompletion: Boolean = true
): ByteWriteChannel {
    if (closeOnCoroutineCompletion) {
        // Pure output represents a socket output channel that is closed when request fully processed or after
        // request sent in case TCP half-close is allowed.
        coroutineContext.job.invokeOnCompletion {
            close(it)
        }
    }

    return GlobalScope.reader(coroutineContext, autoFlush = true) {
        channel.copyTo(this@withoutClosePropagation, Long.MAX_VALUE)
        this@withoutClosePropagation.flush()
    }.channel
}
